// Mapa de productos desde Get Products (5 páginas)
const productMap = {};
for (const p of $('Get Products').all()) {
  for (const prod of (p.json.results || [])) {
    productMap[prod.code] = { name: prod.name, category: (prod.account_group && prod.account_group.name) || 'Sin categoria' };
  }
}

// Facturas nuevas
const invoices = [];
for (const p of $input.all()) {
  for (const inv of (p.json.results || [])) invoices.push(inv);
}

// Dedup: facturas ya procesadas
const sd = $getWorkflowStaticData('global');
if (!sd.ghlEnriquecidas) sd.ghlEnriquecidas = {};
const done = sd.ghlEnriquecidas;
// limpiar entradas > 90 días
const cutoff = Date.now() - 90*86400000;
for (const k of Object.keys(done)) { if (done[k] < cutoff) delete done[k]; }

const BLOCKED = new Set(['222222222222','7777777777777']);
function isNIT(id) {
  const raw = String(id||'').trim();
  if (/\d{8,9}-\d$/.test(raw)) return true;
  const d = raw.replace(/[^0-9]/g,'');
  if (d.length !== 9 && d.length !== 10) return false;
  return /^(800|811|812|813|820|830|832|860|890|891|892|899|900|901|902)/.test(d);
}
function slug(s) {
  return String(s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'')
    .replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,40);
}
function fxOf(doc) { return (doc.currency && doc.currency.exchange_rate) ? Number(doc.currency.exchange_rate) : 1; }
function itemSub(it) { return Number(it.price||0)*Number(it.quantity||1) - Number((it.discount&&it.discount.value)||0); }
const esMod = nm => /^(sel\s|no aplica)/i.test(nm);

// Agrupar por cédula (solo persona natural, facturas no procesadas)
const byCed = {};
for (const inv of invoices) {
  if (done[inv.id]) continue;
  const ced = String((inv.customer && inv.customer.identification) || '').replace(/[^0-9]/g,'');
  if (!ced || BLOCKED.has(ced) || isNIT(ced)) continue;
  if (!byCed[ced]) byCed[ced] = [];
  byCed[ced].push(inv);
}

const out = [];
for (const [ced, invs] of Object.entries(byCed)) {
  invs.sort((a,b) => String(a.date).localeCompare(String(b.date)));
  let total = 0; const prodTotals = {}; const tags = new Set(); const notas = [];
  for (const inv of invs) {
    const fx = fxOf(inv);
    let invTotal = 0; const lines = [];
    for (const it of (inv.items || [])) {
      const s = itemSub(it) * fx;
      total += s; invTotal += s;
      const prod = productMap[it.code] || { name: it.description || it.code, category: 'Sin categoria' };
      lines.push('• ' + prod.name + ' x' + Number(it.quantity));
      if (s <= 0 || esMod(prod.name)) continue;
      prodTotals[prod.name] = (prodTotals[prod.name]||0) + s;
      tags.add('cat:' + slug(prod.category));
      tags.add('prod:' + slug(prod.name));
    }
    notas.push('🛒 Compra ' + inv.name + ' — ' + String(inv.date).slice(0,10) + '\n' + lines.join('\n') + '\nTotal: $' + Math.round(invTotal).toLocaleString('es-CO'));
  }
  const lastInv = invs[invs.length-1];
  const lastProds = (lastInv.items||[])
    .map(it => ({ nm: (productMap[it.code]||{}).name || it.description || it.code, s: itemSub(it) }))
    .filter(x => x.s > 0 && !esMod(x.nm)).map(x => x.nm).slice(0,5).join(', ');
  const fav = Object.entries(prodTotals).sort((a,b)=>b[1]-a[1])[0];
  out.push({ json: {
    ced, invoiceIds: invs.map(i=>i.id),
    totalNuevo: Math.round(total), comprasNuevas: invs.length,
    lastDate: String(lastInv.date).slice(0,10), lastProds,
    favNuevo: fav ? fav[0] : '', favMontoNuevo: fav ? Math.round(fav[1]) : 0,
    tags: [...tags], notas
  }});
}
return out.length ? out : [];

// Combina resultado de búsqueda GHL con los datos por cédula
const CF = {
  cedula: '4C6TxwNRElYAB1HFkJb4', totalGastado: '4XeNF2WH8ENigBGp2p3y',
  cantidad: 'ZgAmsrhK3c9txQDdamoK', ultimaFecha: 'awOZU9UMdqsEtOzeohst',
  ultimosProds: '5kLgbedHcudIHOb4QCYs', prodFavorito: 'M2v7Jx24UrBCKxdULFp0'
};
const buildItems = $('Build Items').all();
const searches = $input.all();
const out = [];
for (let i = 0; i < buildItems.length; i++) {
  const b = buildItems[i].json;
  const s = (searches[i] && searches[i].json) || {};
  const contact = (s.contacts || [])[0];
  let totalPrev = 0, cantPrev = 0, favPrev = '', favMontoPrev = 0;
  if (contact) {
    for (const cf of (contact.customFields || [])) {
      if (cf.id === CF.totalGastado) totalPrev = Number(cf.value) || 0;
      if (cf.id === CF.cantidad) cantPrev = Number(cf.value) || 0;
      if (cf.id === CF.prodFavorito) favPrev = String(cf.value || '');
    }
  }
  // favorito: si el nuevo monto supera, cambia; si no hay previo, usa el nuevo
  const fav = b.favNuevo && (!favPrev || b.favMontoNuevo >= totalPrev * 0.3) ? (favPrev && b.favMontoNuevo < favMontoPrev ? favPrev : b.favNuevo) : (favPrev || b.favNuevo);
  out.push({ json: {
    ...b,
    contactId: contact ? contact.id : null,
    necesitaCrear: !contact,
    fields: [
      { id: CF.totalGastado, value: totalPrev + b.totalNuevo },
      { id: CF.cantidad, value: cantPrev + b.comprasNuevas },
      { id: CF.ultimaFecha, value: b.lastDate },
      { id: CF.ultimosProds, value: b.lastProds },
      { id: CF.prodFavorito, value: fav }
    ]
  }});
}
return out;

// Solo cédulas que necesitan crear contacto → buscar datos en Siigo
const items = $input.all().filter(i => i.json.necesitaCrear);
return items.length ? items : [];

// Prepara body de creación de contacto con datos del cliente Siigo
const lookups = $input.all();
const pending = $('Prep Actions').all().filter(i => i.json.necesitaCrear);
const out = [];
function normPhone(p) {
  const d = String(p||'').replace(/[^0-9]/g,'');
  if (d.length === 10 && d.startsWith('3')) return '+57' + d;
  if (d.length === 12 && d.startsWith('57')) return '+' + d;
  return null;
}
for (let i = 0; i < pending.length; i++) {
  const b = pending[i].json;
  const cust = (((lookups[i]||{}).json||{}).results || [])[0] || {};
  const nameArr = cust.name || [];
  const body = {
    locationId: 'jzrg6bPH71ccLohGddsN',
    firstName: nameArr[0] || 'Cliente',
    lastName: nameArr.slice(1).join(' ') || b.ced,
    customFields: [{ id: '4C6TxwNRElYAB1HFkJb4', value: b.ced }]
  };
  const phone = normPhone(cust.phones && cust.phones[0] && cust.phones[0].number);
  const email = cust.contacts && cust.contacts[0] && cust.contacts[0].email;
  if (phone) body.phone = phone;
  if (email) body.email = email;
  out.push({ json: { ...b, createBody: body } });
}
return out.length ? out : [];

// Junta contactos existentes + creados, genera items de acción para los updates
const prep = $('Prep Actions').all();
let created = [];
try { created = $('Create Contact').all(); } catch(e) {}
const createdByCed = {};
for (let i = 0; i < created.length; i++) {
  const src = $('Merge Create').all()[i];
  const cid = (created[i].json.contact && created[i].json.contact.id) || (created[i].json.meta && created[i].json.meta.contactId);
  if (src && cid) createdByCed[src.json.ced] = cid;
}
const out = [];
for (const p of prep) {
  const b = p.json;
  const contactId = b.contactId || createdByCed[b.ced];
  if (!contactId) continue;
  out.push({ json: { ...b, contactId } });
}
return out.length ? out : [];

// Un item por nota (contactId + texto)
const out = [];
for (const p of $input.all()) {
  for (const nota of (p.json.notas || [])) {
    out.push({ json: { contactId: p.json.contactId, nota } });
  }
}
return out.length ? out : [];

// Marca las facturas como procesadas en staticData
const sd = $getWorkflowStaticData('global');
if (!sd.ghlEnriquecidas) sd.ghlEnriquecidas = {};
let count = 0;
for (const p of $('Finalize').all()) {
  for (const id of (p.json.invoiceIds || [])) { sd.ghlEnriquecidas[id] = Date.now(); count++; }
}
return [{ json: { procesadas: count, ts: new Date().toISOString() } }];
